+// IdempotencyStore caches responses by idempotency key.
+type IdempotencyStore struct {
+	mu      sync.RWMutex
+	entries map[string]*idempotencyEntry
+	ttl     time.Duration
+}
+
+type idempotencyEntry struct {
+	response   []byte
+	statusCode int
+	createdAt  time.Time
+}
+
+// NewIdempotencyStore creates an idempotency cache with the given TTL.
+func NewIdempotencyStore(ttl time.Duration) *IdempotencyStore {
+	if ttl <= 0 {
+		ttl = 24 * time.Hour
+	}
+	store := &IdempotencyStore{
+		entries: make(map[string]*idempotencyEntry),
+		ttl:     ttl,
+	}
+	// Start cleanup goroutine
+	go store.cleanup()
+	return store
+}
+
+func (s *IdempotencyStore) cleanup() {
+	ticker := time.NewTicker(time.Minute)
+	for range ticker.C {
+		s.mu.Lock()
+		now := time.Now()
+		for key, entry := range s.entries {
+			if now.Sub(entry.createdAt) > s.ttl {
+				delete(s.entries, key)
+			}
+		}
+		s.mu.Unlock()
+	}
+}
+
+// Get returns a cached response for the idempotency key.
+func (s *IdempotencyStore) Get(key string) ([]byte, int, bool) {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	entry, ok := s.entries[key]
+	if !ok {
+		return nil, 0, false
+	}
+	if time.Since(entry.createdAt) > s.ttl {
+		return nil, 0, false
+	}
+	return entry.response, entry.statusCode, true
+}
+
+// Set stores a response for the idempotency key.
+func (s *IdempotencyStore) Set(key string, response []byte, statusCode int) {
+	s.mu.Lock()
+	defer s.mu.Unlock()
+	s.entries[key] = &idempotencyEntry{
+		response:   response,
+		statusCode: statusCode,
+		createdAt:  time.Now(),
+	}
+}
+
+// Job represents an asynchronous operation.
+type Job struct {
+	ID        string                 `json:"id"`
+	Type      string                 `json:"type"`
+	Status    JobStatus              `json:"status"`
+	Progress  float64                `json:"progress,omitempty"`
+	Result    map[string]interface{} `json:"result,omitempty"`
+	Error     string                 `json:"error,omitempty"`
+	CreatedAt string                 `json:"created_at"`
+	UpdatedAt string                 `json:"updated_at"`
+}
+
+// JobStatus represents the state of a job.
+type JobStatus string
+
+const (
+	JobStatusPending   JobStatus = "pending"
+	JobStatusRunning   JobStatus = "running"
+	JobStatusCompleted JobStatus = "completed"
+	JobStatusFailed    JobStatus = "failed"
+	JobStatusCancelled JobStatus = "cancelled"
+)
+
+// JobStore manages asynchronous jobs.
+type JobStore struct {
+	mu   sync.RWMutex
+	jobs map[string]*Job
+}
+
+// NewJobStore creates a new job store.
+func NewJobStore() *JobStore {
+	return &JobStore{
+		jobs: make(map[string]*Job),
+	}
+}
+
+// Create creates a new job.
+func (s *JobStore) Create(jobType string) *Job {
+	s.mu.Lock()
+	defer s.mu.Unlock()
+	id := generateRequestID()
+	now := time.Now().UTC().Format(time.RFC3339)
+	job := &Job{
+		ID:        id,
+		Type:      jobType,
+		Status:    JobStatusPending,
+		CreatedAt: now,
+		UpdatedAt: now,
+	}
+	s.jobs[id] = job
+	return job
+}
+
+// Get retrieves a job by ID.
+func (s *JobStore) Get(id string) *Job {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	return s.jobs[id]
+}
+
+// Update updates a job's status and progress.
+func (s *JobStore) Update(id string, status JobStatus, progress float64, result map[string]interface{}, errMsg string) {
+	s.mu.Lock()
+	defer s.mu.Unlock()
+	job, ok := s.jobs[id]
+	if !ok {
+		return
+	}
+	job.Status = status
+	job.Progress = progress
+	job.Result = result
+	job.Error = errMsg
+	job.UpdatedAt = time.Now().UTC().Format(time.RFC3339)
+}
+
+// List returns all jobs.
+func (s *JobStore) List() []*Job {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	jobs := make([]*Job, 0, len(s.jobs))
+	for _, job := range s.jobs {
+		jobs = append(jobs, job)
+	}
+	return jobs
+}
+
+// Delete removes a job.
+func (s *JobStore) Delete(id string) bool {
+	s.mu.Lock()
+	defer s.mu.Unlock()
+	if _, ok := s.jobs[id]; !ok {
+		return false
+	}
+	delete(s.jobs, id)
+	return true
+}
