+	s.jobStore.Update(jobID, JobStatusCancelled, job.Progress, nil, "cancelled by user")
+
+	writeSuccessResponse(w, http.StatusOK, map[string]interface{}{
+		"job": s.jobStore.Get(jobID),
+	}, reqID)
